+        let source = MockCheckpointStorage::new(consumers, checkpoints);
+        let target = MockCheckpointStorage::empty_target();
+        let engine = MigrationEngine::new(MigrationConfig::default());
+
+        let manifest = MigrationManifest {
+            first_ordinal: 0,
+            last_ordinal: 10,
+            ..Default::default()
