+    async fn test_m3_mixed_valid_and_stale_consumers() {
+        let consumers = vec![
+            make_consumer_lag("good", 2),
+            make_consumer_lag("stale", 0),
+        ];
+        let mut checkpoints = HashMap::new();
+        checkpoints.insert("good".to_string(), make_checkpoint("good", 5));
